package com.example.expressionphotobooth;

import android.content.Context;
import android.graphics.Color;
import android.graphics.drawable.ColorDrawable;
import android.text.TextUtils;
import android.view.LayoutInflater;
import android.view.View;
import android.widget.TextView;

import androidx.appcompat.app.AlertDialog;

import com.google.android.material.button.MaterialButton;
import com.google.android.material.dialog.MaterialAlertDialogBuilder;

import java.util.List;

public final class HelpDialogUtils {

    private HelpDialogUtils() {
    }

    public static void showPhotoboothHelp(Context context, String title, String subtitle, List<String> bullets) {
        View dialogView = LayoutInflater.from(context).inflate(R.layout.dialog_help_photobooth, null, false);

        TextView tvTitle = dialogView.findViewById(R.id.tvHelpTitle);
        TextView tvSubtitle = dialogView.findViewById(R.id.tvHelpSubtitle);
        TextView[] bulletTexts = new TextView[] {
                dialogView.findViewById(R.id.tvBullet1),
                dialogView.findViewById(R.id.tvBullet2),
                dialogView.findViewById(R.id.tvBullet3),
                dialogView.findViewById(R.id.tvBullet4)
        };
        View[] bulletRows = new View[] {
                dialogView.findViewById(R.id.rowBullet1),
                dialogView.findViewById(R.id.rowBullet2),
                dialogView.findViewById(R.id.rowBullet3),
                dialogView.findViewById(R.id.rowBullet4)
        };
        MaterialButton btnGotIt = dialogView.findViewById(R.id.btnGotIt);

        tvTitle.setText(title);
        if (TextUtils.isEmpty(subtitle)) {
            tvSubtitle.setVisibility(View.GONE);
        } else {
            tvSubtitle.setVisibility(View.VISIBLE);
            tvSubtitle.setText(subtitle);
        }

        int bulletCount = bullets == null ? 0 : Math.min(bullets.size(), bulletTexts.length);
        for (int i = 0; i < bulletRows.length; i++) {
            if (i < bulletCount) {
                bulletRows[i].setVisibility(View.VISIBLE);
                bulletTexts[i].setText(bullets.get(i));
            } else {
                bulletRows[i].setVisibility(View.GONE);
            }
        }

        AlertDialog dialog = new MaterialAlertDialogBuilder(context)
                .setView(dialogView)
                .create();

        btnGotIt.setOnClickListener(v -> dialog.dismiss());

        dialog.show();
        if (dialog.getWindow() != null) {
            dialog.getWindow().setBackgroundDrawable(new ColorDrawable(Color.TRANSPARENT));
        }
    }
}

package com.example.expressionphotobooth;

import android.Manifest;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.graphics.Rect;
import android.media.MediaActionSound;
import android.net.Uri;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.util.Log;
import android.util.Size;
import android.view.Gravity;
import android.view.View;
import android.widget.Button;
import android.widget.ImageView;
import android.widget.ImageButton;
import android.widget.LinearLayout;
import android.widget.TextView;
import android.widget.Toast;

import androidx.activity.EdgeToEdge;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.camera.core.ImageAnalysis;
import androidx.camera.core.ImageCapture;
import androidx.camera.core.ImageCaptureException;
import androidx.camera.core.CameraSelector;
import androidx.camera.core.Camera;
import androidx.camera.core.Preview;
import androidx.camera.lifecycle.ProcessCameraProvider;
import androidx.camera.view.PreviewView;
import androidx.cardview.widget.CardView;
import androidx.constraintlayout.widget.ConstraintLayout;
import androidx.core.content.ContextCompat;
import androidx.core.graphics.Insets;
import androidx.core.view.ViewCompat;
import androidx.core.view.WindowInsetsCompat;

import com.bumptech.glide.Glide;
import com.example.expressionphotobooth.domain.model.SessionState;
import com.example.expressionphotobooth.domain.repository.SessionRepository;
import com.example.expressionphotobooth.domain.usecase.ExpressionAnalyzer;
import com.example.expressionphotobooth.domain.usecase.GestureAnalyzer;
import com.google.android.material.appbar.MaterialToolbar;
import com.google.android.material.progressindicator.LinearProgressIndicator;
import com.google.common.util.concurrent.ListenableFuture;

import java.io.File;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutionException;

public class MainActivity extends AppCompatActivity {

    private static final int CAMERA_PERMISSION_CODE = 100;
    private static final String TAG = "CameraX";
    private PreviewView viewFinder;
    private CardView previewCard;
    private AiOverlayView aiOverlayView;
    private View captureButton;
    private ImageButton flashButton;
    private ImageButton soundButton;
    private Button squareRatioButton;
    private Button wideRatioButton;
    private TextView tvCountdown;
    private TextView tvCaptureStatus;
    private LinearLayout dotContainer;
    private LinearProgressIndicator captureProgress;
    private ImageView ivLastCapturePreview;
    private View cardLastCapture;
    private View captureFlashOverlay;
    private ImageCapture imageCapture;
    private ImageAnalysis imageAnalysis;
    private ExpressionAnalyzer expressionAnalyzer;
    private GestureAnalyzer gestureAnalyzer;
    private boolean isWaitingForExpression = false;
    private String targetExpression = "HI"; // Default to Hi gesture
    private int maxPhotos;
    private int capturedCount = 0;
    private final List<Uri> savedImageUris = new ArrayList<>();
    private ProcessCameraProvider cameraProvider;
    private Camera camera;
    private CameraSelector cameraSelector = CameraSelector.DEFAULT_FRONT_CAMERA;
    private boolean isSquareRatio = true;
    private boolean isCapturingSequence = false;
    private boolean isExpressionMode = false; // Main AI Mode flag
    private boolean isHandGestureMode = false; // Sub AI Mode: Hand (default = false, Face is default)
    private boolean isFaceExpressionMode = true; // Sub AI Mode: Face (default = true)
    private boolean isFlashPreferredOn = false;
    private boolean isScreenFlashStrong = false;
    private boolean isSoundEnabled = true;
    private SessionRepository sessionRepository;
    private SessionState sessionState;
    private MediaActionSound shutterSound;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        EdgeToEdge.enable(this);
        setContentView(R.layout.activity_main);

        AppContainer appContainer = (AppContainer) getApplication();
        sessionRepository = appContainer.getSessionRepository();
        sessionState = sessionRepository.getSession();
        isFlashPreferredOn = sessionState.isFlashEnabled();
        isScreenFlashStrong = sessionState.isScreenFlashStrong();
        isSoundEnabled = sessionState.isSoundEnabled();
        setupToolbar();

        shutterSound = new MediaActionSound();
        shutterSound.load(MediaActionSound.SHUTTER_CLICK);

        expressionAnalyzer = new ExpressionAnalyzer();
        gestureAnalyzer = new GestureAnalyzer();

        // Ánh xạ View
        viewFinder = findViewById(R.id.viewFinder);
        previewCard = findViewById(R.id.previewCard);
        aiOverlayView = (AiOverlayView) findViewById(R.id.overlayView);
        captureButton = findViewById(R.id.btnCapture);
        flashButton = findViewById(R.id.btnFlash);
        soundButton = findViewById(R.id.btnSound);
        tvCountdown = findViewById(R.id.tvCountdown);
        squareRatioButton = findViewById(R.id.btnRatioSquare);
        wideRatioButton = findViewById(R.id.btnRatioWide);
        tvCaptureStatus = findViewById(R.id.tvCaptureStatus);
        dotContainer = findViewById(R.id.dotContainer);
        captureProgress = findViewById(R.id.captureProgress);
        ivLastCapturePreview = findViewById(R.id.ivLastCapturePreview);
        cardLastCapture = findViewById(R.id.cardLastCapture);
        captureFlashOverlay = findViewById(R.id.captureFlashOverlay);

        // Nhận số lượng ảnh từ trang trước
        maxPhotos = getIntent().getIntExtra(IntentKeys.EXTRA_PHOTO_COUNT, sessionState.getPhotoCount());
        sessionState.setPhotoCount(maxPhotos);
        sessionRepository.saveSession(sessionState);
        initCaptureUi();

        captureButton.setEnabled(false);
        captureButton.setOnClickListener(v -> startPhotoSequence());

        View btnSwitchCamera = findViewById(R.id.btnSwitchCamera);
        if (btnSwitchCamera != null) {
            btnSwitchCamera.setOnClickListener(v -> {
                if (cameraProvider != null && !isCapturingSequence) {
                    if (cameraSelector == CameraSelector.DEFAULT_FRONT_CAMERA) {
                        cameraSelector = CameraSelector.DEFAULT_BACK_CAMERA;
                    } else {
                        cameraSelector = CameraSelector.DEFAULT_FRONT_CAMERA;
                    }
                    bindCameraUseCases();
                }
            });
        }

        if (flashButton != null) {
            flashButton.setOnClickListener(v -> toggleFlash());
            flashButton.setOnLongClickListener(v -> {
                toggleScreenFlashStrength();
                return true;
            });
        }

        if (soundButton != null) {
            updateSoundIcon();
            soundButton.setOnClickListener(v -> toggleSound());
        }

        squareRatioButton.setOnClickListener(v -> {
            if (!isSquareRatio) {
                isSquareRatio = true;
                applyPreviewRatio();
                if (cameraProvider != null) bindCameraUseCases();
            }
        });

        wideRatioButton.setOnClickListener(v -> {
            if (isSquareRatio) {
                isSquareRatio = false;
                applyPreviewRatio();
                if (cameraProvider != null) bindCameraUseCases();
            }
        });

        com.google.android.material.button.MaterialButtonToggleGroup modeGroup = findViewById(R.id.modeContainer);
        View aiSubGroup = findViewById(R.id.aiSelectionContainer);
        modeGroup.addOnButtonCheckedListener((group, checkedId, isChecked) -> {
            if (isChecked) {
                isExpressionMode = (checkedId == R.id.btnModeExpression);
                aiSubGroup.setVisibility(isExpressionMode ? View.VISIBLE : View.GONE);
                if (isExpressionMode) {
                    Toast.makeText(this, "Chế độ AI: Hãy chọn kiểu detect!", Toast.LENGTH_SHORT).show();
                } else {
                    Toast.makeText(this, "Chế độ tự động: Đếm ngược 3 giây", Toast.LENGTH_SHORT).show();
                }
            }
        });

        com.google.android.material.button.MaterialButtonToggleGroup aiSubSelector = 
            (com.google.android.material.button.MaterialButtonToggleGroup) findViewById(R.id.aiSelectionContainer);

        // Đồng bộ trạng thái ban đầu theo nút đang được check trong XML (btnAiFace)
        isHandGestureMode = false;
        isFaceExpressionMode = true;

        aiSubSelector.addOnButtonCheckedListener((group, checkedId, isChecked) -> {
            if (!isChecked) return; // chỉ xử lý khi nút được chọn
            isHandGestureMode = (checkedId == R.id.btnAiHand);
            isFaceExpressionMode = (checkedId == R.id.btnAiFace);
            if (isFaceExpressionMode) {
                Toast.makeText(this, "Đã chuyển sang: Nhận diện khuôn mặt", Toast.LENGTH_SHORT).show();
            } else {
                Toast.makeText(this, "Đã chuyển sang: Nhận diện hành động", Toast.LENGTH_SHORT).show();
            }
        });

        applyPreviewRatio();

        View mainView = findViewById(R.id.main);
        if (mainView != null) {
            ViewCompat.setOnApplyWindowInsetsListener(mainView, (v, insets) -> {
                Insets systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars());
                v.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom);
                return insets;
            });
        }

        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
            startCamera();
        } else {
            requestCameraPermission();
        }
    }

    private void requestCameraPermission() {
        requestPermissions(new String[]{Manifest.permission.CAMERA}, CAMERA_PERMISSION_CODE);
    }

    private void startCamera() {
        ListenableFuture<ProcessCameraProvider> cameraProviderFuture = ProcessCameraProvider.getInstance(this);
        cameraProviderFuture.addListener(() -> {
            try {
                cameraProvider = cameraProviderFuture.get();
                bindCameraUseCases();
            } catch (ExecutionException | InterruptedException e) {
                Log.e(TAG, "Failed to start camera", e);
            }
        }, ContextCompat.getMainExecutor(this));
    }

    private void bindCameraUseCases() {
        if (cameraProvider == null) return;

        Preview preview = new Preview.Builder().build();
        imageCapture = buildImageCaptureUseCase();
        imageAnalysis = new ImageAnalysis.Builder()
                .setBackpressureStrategy(ImageAnalysis.STRATEGY_KEEP_ONLY_LATEST)
                .build();

        imageAnalysis.setAnalyzer(ContextCompat.getMainExecutor(this), imageProxy -> {
            boolean isWaiting = isWaitingForExpression;
            if (isHandGestureMode && gestureAnalyzer != null) {
                gestureAnalyzer.analyzeImageProxy(imageProxy, (gesture, box) -> {
                    // Luôn hiện khung xanh để test kể cả khi không trong mode capture
                    updateAiOverlay(box, gesture, android.graphics.Color.parseColor("#00E676"),
                            imageProxy.getWidth(), imageProxy.getHeight(),
                            imageProxy.getImageInfo().getRotationDegrees());
                    // Chỉ trigger nếu gesture nằm trong phần HIỂN THỊ của camera
                    if (isWaiting && targetExpression.equals(gesture)
                            && isBoxVisibleInPreview(box, imageProxy.getWidth(), imageProxy.getHeight(),
                                                    imageProxy.getImageInfo().getRotationDegrees())) {
                        triggerImmediateCapture();
                    }
                });
            } else if (isFaceExpressionMode && expressionAnalyzer != null) {
                expressionAnalyzer.analyzeImageProxy(imageProxy, (expression, faceBox) -> {
                    updateAiOverlay(faceBox, expression, android.graphics.Color.parseColor("#00B0FF"),
                            imageProxy.getWidth(), imageProxy.getHeight(),
                            imageProxy.getImageInfo().getRotationDegrees());
                    if (isWaiting && targetExpression.equals(expression)
                            && isBoxVisibleInPreview(faceBox, imageProxy.getWidth(), imageProxy.getHeight(),
                                                    imageProxy.getImageInfo().getRotationDegrees())) {
                        triggerImmediateCapture();
                    }
                });
            } else {
                imageProxy.close();
            }
        });

        preview.setSurfaceProvider(viewFinder.getSurfaceProvider());

        try {
            cameraProvider.unbindAll();
            camera = cameraProvider.bindToLifecycle(this, cameraSelector, preview, imageCapture, imageAnalysis);
            captureButton.setEnabled(true);
            applyFlashMode();
            updateFlashAvailability();
        } catch (Exception e) {
            Log.e(TAG, "Failed to bind camera use cases", e);
            captureButton.setEnabled(false);
            if (flashButton != null) flashButton.setEnabled(false);
            Toast.makeText(this, R.string.camera_not_ready, Toast.LENGTH_SHORT).show();
        }
    }

    private ImageCapture buildImageCaptureUseCase() {
        ImageCapture.Builder builder = new ImageCapture.Builder()
                .setCaptureMode(ImageCapture.CAPTURE_MODE_MINIMIZE_LATENCY);

        if (isSquareRatio) {
            builder.setTargetResolution(new Size(1080, 1080));
        } else {
            builder.setTargetAspectRatio(androidx.camera.core.AspectRatio.RATIO_16_9);
        }
        return builder.build();
    }

    private void applyPreviewRatio() {
        ConstraintLayout.LayoutParams params = (ConstraintLayout.LayoutParams) previewCard.getLayoutParams();
        params.dimensionRatio = isSquareRatio ? "1:1" : "16:9";
        previewCard.setLayoutParams(params);
    }

    private void startPhotoSequence() {
        if (isCapturingSequence) return;

        capturedCount = 0;
        savedImageUris.clear();
        cardLastCapture.setVisibility(View.GONE);
        isCapturingSequence = true;
        captureButton.setEnabled(false);
        squareRatioButton.setEnabled(false);
        wideRatioButton.setEnabled(false);
        findViewById(R.id.modeContainer).setEnabled(false);
        if (flashButton != null) flashButton.setEnabled(false);
        updateCaptureProgressUi();
        updateCaptureStatus(getString(R.string.capture_status_starting, maxPhotos));

        // Bắt đầu chuỗi chụp
        startCountdownAndCapture();
    }

    private void triggerImmediateCapture() {
        isWaitingForExpression = false;
        tvCountdown.post(() -> {
            if (aiOverlayView != null) aiOverlayView.updateOverlay(null, "");
            tvCountdown.setVisibility(View.GONE);
            takePhoto();
        });
    }

    private void updateAiOverlay(Rect box, String label, int color, int imgW, int imgH, int rotation) {
        if (aiOverlayView == null) return;
        aiOverlayView.post(() -> {
            java.util.List<Rect> boxes = new java.util.ArrayList<>();
            int viewW = aiOverlayView.getWidth();
            int viewH = aiOverlayView.getHeight();

            if (box != null && viewW > 0 && viewH > 0) {
                // Sau khi rotation, portrait device: imgW/imgH có thể được đảo
                float srcW = (rotation == 90 || rotation == 270) ? (float) imgH : (float) imgW;
                float srcH = (rotation == 90 || rotation == 270) ? (float) imgW : (float) imgH;

                // Tính CENTER_CROP: tìm scale để cả 2 chiều đều >= view (giống scaleType=centerCrop)
                float scaleX = viewW / srcW;
                float scaleY = viewH / srcH;
                float scale = Math.max(scaleX, scaleY); // CENTER_CROP lấy scale lớn nhất

                // Phần thừa bị crop ở giữa
                float cropOffsetX = (srcW * scale - viewW) / 2f;
                float cropOffsetY = (srcH * scale - viewH) / 2f;

                // Chuyển đổi: pixel ảnh -> pixel view (sau crop)
                int left   = (int)(box.left   * scale - cropOffsetX);
                int top    = (int)(box.top    * scale - cropOffsetY);
                int right  = (int)(box.right  * scale - cropOffsetX);
                int bottom = (int)(box.bottom * scale - cropOffsetY);

                // Mirror X cho camera trước
                if (cameraSelector == CameraSelector.DEFAULT_FRONT_CAMERA) {
                    int newLeft = viewW - right;
                    right = viewW - left;
                    left = newLeft;
                }

                // Clip vào phần hiển thị thực tế của overlay
                left   = Math.max(0, left);
                top    = Math.max(0, top);
                right  = Math.min(viewW, right);
                bottom = Math.min(viewH, bottom);

                // Chỉ vẽ nếu hộp hợp lệ
                if (left < right && top < bottom) {
                    boxes.add(new Rect(left, top, right, bottom));
                }
            }
            aiOverlayView.updateOverlay(boxes, label, color);
        });
    }

    // Overload for calls without images (e.g. clearing)
    private void updateAiOverlay(Rect box, String label) {
        updateAiOverlay(box, label, android.graphics.Color.parseColor("#00E676"), 640, 480, 90);
    }

    /**
     * Kiểm tra xem trung tâm bounding box có nằm trong phần hiển thị thực tế
     * (sau CENTER_CROP) của camera preview không.
     */
    private boolean isBoxVisibleInPreview(Rect box, int imgW, int imgH, int rotation) {
        if (box == null || aiOverlayView == null) return false;
        int viewW = aiOverlayView.getWidth();
        int viewH = aiOverlayView.getHeight();
        if (viewW <= 0 || viewH <= 0) return true; // biến mết thì cứ cho qua

        float srcW = (rotation == 90 || rotation == 270) ? (float) imgH : (float) imgW;
        float srcH = (rotation == 90 || rotation == 270) ? (float) imgW : (float) imgH;

        float scale = Math.max(viewW / srcW, viewH / srcH);
        float cropOffsetX = (srcW * scale - viewW) / 2f;
        float cropOffsetY = (srcH * scale - viewH) / 2f;

        // Tính trung tâm hộp sau transform
        float cx = ((box.left + box.right) / 2f) * scale - cropOffsetX;
        float cy = ((box.top + box.bottom) / 2f) * scale - cropOffsetY;

        // Mirror cho camera trước
        if (cameraSelector == CameraSelector.DEFAULT_FRONT_CAMERA) {
            cx = viewW - cx;
        }

        return cx >= 0 && cx <= viewW && cy >= 0 && cy <= viewH;
    }

    private void startCountdownAndCapture() {
        if (capturedCount >= maxPhotos) {
            isCapturingSequence = false;
            updateCaptureStatus(getString(R.string.capture_status_done, maxPhotos));
            findViewById(R.id.modeContainer).setEnabled(true);
            findViewById(R.id.aiSelectionContainer).setEnabled(true);
            goToSelectionPage();
            return;
        }

        tvCountdown.setVisibility(View.VISIBLE);
        int nextShot = capturedCount + 1;

        if (isExpressionMode) {
            if (isHandGestureMode) {
                if (nextShot % 2 != 0) {
                    targetExpression = "HI";
                    tvCountdown.setText("✌️");
                    updateCaptureStatus("Chụp " + nextShot + ": Giơ tay Hi nào!");
                } else {
                    targetExpression = "HEART";
                    tvCountdown.setText("❤️");
                    updateCaptureStatus("Chụp " + nextShot + ": Thả tim xem!");
                }
            } else {
                // Face mode
                if (nextShot % 2 != 0) {
                    targetExpression = "SMILE";
                    tvCountdown.setText(":D");
                    updateCaptureStatus("Chụp " + nextShot + ": Cười lên nào!");
                } else {
                    targetExpression = "WINK_RIGHT"; // Simple specific wink
                    tvCountdown.setText(";)");
                    updateCaptureStatus("Chụp " + nextShot + ": Nháy mắt cái nào!");
                }
            }

            // Lock indicator...
            new Handler(Looper.getMainLooper()).postDelayed(() -> {
                if (isCapturingSequence) {
                    isWaitingForExpression = true;
                    // Fallback 7s
                    new Handler(Looper.getMainLooper()).postDelayed(() -> {
                        if (isCapturingSequence && isWaitingForExpression) {
                            triggerImmediateCapture();
                        }
                    }, 7000);
                }
            }, 1000);
        } else {
            // Standard Countdown Mode
            runCountdown(3);
        }
    }

    private void runCountdown(int seconds) {
        if (seconds > 0) {
            tvCountdown.setText(String.valueOf(seconds));
            int nextShot = Math.min(capturedCount + 1, maxPhotos);
            updateCaptureStatus(getString(R.string.capture_status_countdown, nextShot, maxPhotos, seconds));
            new Handler(Looper.getMainLooper()).postDelayed(() -> {
                if (isCapturingSequence && !isExpressionMode) {
                    runCountdown(seconds - 1);
                }
            }, 1000);
        } else {
            tvCountdown.setVisibility(View.GONE);
            takePhoto();
        }
    }

    private void takePhoto() {
        if (imageCapture == null) {
            isCapturingSequence = false;
            captureButton.setEnabled(true);
            return;
        }

        File photoFile = new File(getExternalFilesDir(null), "photo_" + System.currentTimeMillis() + ".jpg");
        ImageCapture.OutputFileOptions outputOptions = new ImageCapture.OutputFileOptions.Builder(photoFile).build();

        Runnable performCapture = () -> imageCapture.takePicture(outputOptions, ContextCompat.getMainExecutor(this),
                new ImageCapture.OnImageSavedCallback() {
                    @Override
                    public void onImageSaved(@NonNull ImageCapture.OutputFileResults outputFileResults) {
                        capturedCount++;
                        Uri savedUri = Uri.fromFile(photoFile);
                        savedImageUris.add(savedUri);
                        showLastCapturePreview(savedUri);
                        if (!shouldUseScreenFlash()) {
                            playCaptureFlash();
                        }

                        // Phát âm thanh chụp hình
                        if (shutterSound != null && isSoundEnabled) {
                            shutterSound.play(MediaActionSound.SHUTTER_CLICK);
                        }

                        updateCaptureProgressUi();
                        updateCaptureStatus(getString(R.string.capture_status_captured, capturedCount, maxPhotos));

                        // Sau khi chụp xong 1 tấm, đợi 1 chút rồi đếm ngược cho tấm tiếp theo
                        new Handler(Looper.getMainLooper()).postDelayed(() -> startCountdownAndCapture(), 1000);
                    }

                    @Override
                    public void onError(@NonNull ImageCaptureException exception) {
                        isCapturingSequence = false;
                        isWaitingForExpression = false;
                        captureButton.setEnabled(true);
                        squareRatioButton.setEnabled(true);
                        wideRatioButton.setEnabled(true);
                        findViewById(R.id.modeContainer).setEnabled(true);
                        updateFlashAvailability();
                        updateCaptureStatus(getString(R.string.capture_status_error));
                        Toast.makeText(MainActivity.this, R.string.capture_failed, Toast.LENGTH_SHORT).show();
                    }
                });

        if (shouldUseScreenFlash()) {
            playScreenFlashThenCapture(performCapture);
        } else {
            performCapture.run();
        }
    }

    private void goToSelectionPage() {
        if (cameraProvider != null) cameraProvider.unbindAll();

        squareRatioButton.setEnabled(true);
        wideRatioButton.setEnabled(true);

        ArrayList<String> uriStrings = new ArrayList<>();
        for (Uri uri : savedImageUris) uriStrings.add(uri.toString());

        sessionState.setCapturedImageUris(uriStrings);
        sessionRepository.saveSession(sessionState);

        Intent intent = new Intent(MainActivity.this, PhotoSelectionActivity.class);
        intent.putStringArrayListExtra(IntentKeys.EXTRA_CAPTURED_IMAGES, uriStrings);
        startActivity(intent);
        finish();
    }

    private void initCaptureUi() {
        captureProgress.setMax(Math.max(maxPhotos, 1));
        captureProgress.setProgress(0);
        dotContainer.removeAllViews();
        for (int i = 0; i < maxPhotos; i++) {
            View dot = new View(this);
            LinearLayout.LayoutParams params = new LinearLayout.LayoutParams(dpToPx(10), dpToPx(10));
            params.setMargins(dpToPx(4), 0, dpToPx(4), 0);
            params.gravity = Gravity.CENTER_VERTICAL;
            dot.setLayoutParams(params);
            dot.setBackgroundResource(R.drawable.bg_capture_dot_inactive);
            dotContainer.addView(dot);
        }
        updateCaptureStatus(getString(R.string.capture_status_ready));
    }

    private void updateCaptureProgressUi() {
        captureProgress.setProgressCompat(capturedCount, true);
        for (int i = 0; i < dotContainer.getChildCount(); i++) {
            View dot = dotContainer.getChildAt(i);
            dot.setBackgroundResource(i < capturedCount ? R.drawable.bg_capture_dot_active : R.drawable.bg_capture_dot_inactive);
        }
    }

    private void updateCaptureStatus(String message) {
        tvCaptureStatus.setText(message);
    }

    private void showLastCapturePreview(Uri uri) {
        cardLastCapture.setVisibility(View.VISIBLE);
        Glide.with(this)
                .load(uri)
                .centerCrop()
                .into(ivLastCapturePreview);
    }

    private void playCaptureFlash() {
        captureFlashOverlay.setVisibility(View.VISIBLE);
        captureFlashOverlay.setAlpha(0.6f);
        captureFlashOverlay.animate()
                .alpha(0f)
                .setDuration(220)
                .withEndAction(() -> captureFlashOverlay.setVisibility(View.GONE))
                .start();
    }

    private void toggleFlash() {
        if (camera == null || imageCapture == null) {
            Toast.makeText(this, R.string.camera_not_ready, Toast.LENGTH_SHORT).show();
            return;
        }
        isFlashPreferredOn = !isFlashPreferredOn;
        sessionState.setFlashEnabled(isFlashPreferredOn);
        sessionRepository.saveSession(sessionState);
        applyFlashMode();
        updateFlashAvailability();
        Toast.makeText(this, isFlashPreferredOn ? R.string.camera_flash_on : R.string.camera_flash_off, Toast.LENGTH_SHORT).show();
    }

    private void toggleScreenFlashStrength() {
        isScreenFlashStrong = !isScreenFlashStrong;
        sessionState.setScreenFlashStrong(isScreenFlashStrong);
        sessionRepository.saveSession(sessionState);
        int levelRes = isScreenFlashStrong ? R.string.camera_screen_flash_level_strong : R.string.camera_screen_flash_level_normal;
        Toast.makeText(this, getString(R.string.camera_screen_flash_level_changed, getString(levelRes)), Toast.LENGTH_SHORT).show();
    }

    private void applyFlashMode() {
        if (imageCapture == null) return;
        imageCapture.setFlashMode(shouldUseHardwareFlash() ? ImageCapture.FLASH_MODE_ON : ImageCapture.FLASH_MODE_OFF);
    }

    private void updateFlashAvailability() {
        if (flashButton == null) return;

        boolean canToggleFlash = camera != null && !isCapturingSequence;
        flashButton.setEnabled(canToggleFlash);
        flashButton.setAlpha(canToggleFlash ? 1f : 0.35f);
        flashButton.setImageResource(isFlashPreferredOn ? R.drawable.ic_flash_on_24 : R.drawable.ic_flash_off_24);
    }

    private void toggleSound() {
        isSoundEnabled = !isSoundEnabled;
        sessionState.setSoundEnabled(isSoundEnabled);
        sessionRepository.saveSession(sessionState);
        updateSoundIcon();
        Toast.makeText(this, isSoundEnabled ? "Đã bật âm thanh" : "Đã tắt âm thanh", Toast.LENGTH_SHORT).show();
    }

    private void updateSoundIcon() {
        if (soundButton != null) {
            soundButton.setImageResource(isSoundEnabled ? R.drawable.ic_sound_on : R.drawable.ic_sound_off);
        }
    }

    private boolean shouldUseHardwareFlash() {
        return isFlashPreferredOn
                && camera != null
                && camera.getCameraInfo().hasFlashUnit()
                && cameraSelector == CameraSelector.DEFAULT_BACK_CAMERA;
    }

    private boolean shouldUseScreenFlash() {
        return isFlashPreferredOn && cameraSelector == CameraSelector.DEFAULT_FRONT_CAMERA;
    }

    private void playScreenFlashThenCapture(Runnable onFlashPeak) {
        float flashPeakAlpha = isScreenFlashStrong ? 1.0f : 0.86f;
        long fadeInDuration = isScreenFlashStrong ? 110L : 90L;
        long fadeOutDuration = isScreenFlashStrong ? 220L : 170L;

        captureFlashOverlay.setVisibility(View.VISIBLE);
        captureFlashOverlay.setAlpha(0f);
        captureFlashOverlay.animate()
                .alpha(flashPeakAlpha)
                .setDuration(fadeInDuration)
                .withEndAction(() -> {
                    onFlashPeak.run();
                    captureFlashOverlay.animate()
                            .alpha(0f)
                            .setDuration(fadeOutDuration)
                            .withEndAction(() -> captureFlashOverlay.setVisibility(View.GONE))
                            .start();
                })
                .start();
    }

    private int dpToPx(int dp) {
        return Math.round(dp * getResources().getDisplayMetrics().density);
    }

    private void setupToolbar() {
        MaterialToolbar toolbar = findViewById(R.id.topAppBar);
        setSupportActionBar(toolbar);
        if (getSupportActionBar() != null) {
            getSupportActionBar().setDisplayHomeAsUpEnabled(true);
            getSupportActionBar().setDisplayShowTitleEnabled(false);
        }
        toolbar.setNavigationIcon(R.drawable.ic_arrow_back_24);
        toolbar.setNavigationOnClickListener(v -> getOnBackPressedDispatcher().onBackPressed());
    }

    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions, @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        if (requestCode == CAMERA_PERMISSION_CODE && grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
            startCamera();
        } else if (requestCode == CAMERA_PERMISSION_CODE) {
            Toast.makeText(this, R.string.camera_permission_required, Toast.LENGTH_SHORT).show();
        }
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (cameraProvider != null) {
            cameraProvider.unbindAll();
        }
        if (shutterSound != null) {
            shutterSound.release();
        }
    }
}

package com.example.expressionphotobooth;

import android.Manifest;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.graphics.Rect;
import android.media.MediaActionSound;
import android.net.Uri;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.util.Log;
import android.util.Size;
import android.view.Gravity;
import android.view.View;
import android.widget.Button;
import android.widget.ImageView;
import android.widget.ImageButton;
import android.widget.LinearLayout;
import android.widget.TextView;
import android.widget.Toast;

import androidx.activity.EdgeToEdge;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.camera.core.ImageAnalysis;
import androidx.camera.core.ImageCapture;
import androidx.camera.core.ImageCaptureException;
import androidx.camera.core.CameraSelector;
import androidx.camera.core.Camera;
import androidx.camera.core.Preview;
import androidx.camera.lifecycle.ProcessCameraProvider;
import androidx.camera.view.PreviewView;
import androidx.cardview.widget.CardView;
import androidx.constraintlayout.widget.ConstraintLayout;
import androidx.core.content.ContextCompat;
import androidx.core.graphics.Insets;
import androidx.core.view.ViewCompat;
import androidx.core.view.WindowInsetsCompat;

import com.bumptech.glide.Glide;
import com.example.expressionphotobooth.domain.model.SessionState;
import com.example.expressionphotobooth.domain.repository.SessionRepository;
import com.example.expressionphotobooth.domain.usecase.ExpressionAnalyzer;
import com.example.expressionphotobooth.domain.usecase.GestureAnalyzer;
import com.google.android.material.appbar.MaterialToolbar;
import com.google.android.material.progressindicator.LinearProgressIndicator;
import com.google.common.util.concurrent.ListenableFuture;

import java.io.File;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutionException;

public class MainActivity extends AppCompatActivity {

    private static final int CAMERA_PERMISSION_CODE = 100;
    private static final int CAPTURE_COUNT = 6;
    private static final String TAG = "CameraX";
    private PreviewView viewFinder;
    private CardView previewCard;
    private AiOverlayView aiOverlayView;
    private View captureButton;
    private ImageButton flashButton;
    private ImageButton soundButton;
    private Button squareRatioButton;
    private Button wideRatioButton;
    private TextView tvCountdown;
    private TextView tvCaptureStatus;
    private LinearLayout dotContainer;
    private LinearProgressIndicator captureProgress;
    private ImageView ivLastCapturePreview;
    private View cardLastCapture;
    private View captureFlashOverlay;
    private ImageCapture imageCapture;
    private ImageAnalysis imageAnalysis;
    private ExpressionAnalyzer expressionAnalyzer;
    private GestureAnalyzer gestureAnalyzer;
    private boolean isWaitingForExpression = false;
    private String targetExpression = "HI"; // Default to Hi gesture
    private int maxPhotos;
    private int capturedCount = 0;
    private final List<Uri> savedImageUris = new ArrayList<>();
    private ProcessCameraProvider cameraProvider;
    private Camera camera;
    private CameraSelector cameraSelector = CameraSelector.DEFAULT_FRONT_CAMERA;
    private boolean isSquareRatio = true;
    private boolean isCapturingSequence = false;
    private boolean isExpressionMode = false; // Main AI Mode flag
    private boolean isHandGestureMode = false; // Sub AI Mode: Hand (default = false, Face is default)
    private boolean isFaceExpressionMode = true; // Sub AI Mode: Face (default = true)
    private boolean isFlashPreferredOn = false;
    private boolean isScreenFlashStrong = false;
    private boolean isSoundEnabled = true;
    private SessionRepository sessionRepository;
    private SessionState sessionState;
    private MediaActionSound shutterSound;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        EdgeToEdge.enable(this);
        setContentView(R.layout.activity_main);

        AppContainer appContainer = (AppContainer) getApplication();
        sessionRepository = appContainer.getSessionRepository();
        sessionState = sessionRepository.getSession();
        isFlashPreferredOn = sessionState.isFlashEnabled();
        isScreenFlashStrong = sessionState.isScreenFlashStrong();
        isSoundEnabled = sessionState.isSoundEnabled();
        setupToolbar();

        shutterSound = new MediaActionSound();
        shutterSound.load(MediaActionSound.SHUTTER_CLICK);

        expressionAnalyzer = new ExpressionAnalyzer();
        gestureAnalyzer = new GestureAnalyzer();

        // Ánh xạ View
        viewFinder = findViewById(R.id.viewFinder);
        previewCard = findViewById(R.id.previewCard);
        aiOverlayView = (AiOverlayView) findViewById(R.id.overlayView);
        captureButton = findViewById(R.id.btnCapture);
        flashButton = findViewById(R.id.btnFlash);
        soundButton = findViewById(R.id.btnSound);
        tvCountdown = findViewById(R.id.tvCountdown);
        squareRatioButton = findViewById(R.id.btnRatioSquare);
        wideRatioButton = findViewById(R.id.btnRatioWide);
        tvCaptureStatus = findViewById(R.id.tvCaptureStatus);
        dotContainer = findViewById(R.id.dotContainer);
        captureProgress = findViewById(R.id.captureProgress);
        ivLastCapturePreview = findViewById(R.id.ivLastCapturePreview);
        cardLastCapture = findViewById(R.id.cardLastCapture);
        captureFlashOverlay = findViewById(R.id.captureFlashOverlay);

        // Camera luôn chụp 6 ảnh; selection phía sau sẽ yêu cầu chọn đúng 4 ảnh.
        maxPhotos = CAPTURE_COUNT;
        initCaptureUi();

        captureButton.setEnabled(false);
        captureButton.setOnClickListener(v -> startPhotoSequence());

        View btnSwitchCamera = findViewById(R.id.btnSwitchCamera);
        if (btnSwitchCamera != null) {
            btnSwitchCamera.setOnClickListener(v -> {
                if (cameraProvider != null && !isCapturingSequence) {
                    if (cameraSelector == CameraSelector.DEFAULT_FRONT_CAMERA) {
                        cameraSelector = CameraSelector.DEFAULT_BACK_CAMERA;
                    } else {
                        cameraSelector = CameraSelector.DEFAULT_FRONT_CAMERA;
                    }
                    bindCameraUseCases();
                }
            });
        }

        if (flashButton != null) {
            flashButton.setOnClickListener(v -> toggleFlash());
            flashButton.setOnLongClickListener(v -> {
                toggleScreenFlashStrength();
                return true;
            });
        }

        if (soundButton != null) {
            updateSoundIcon();
            soundButton.setOnClickListener(v -> toggleSound());
        }

        squareRatioButton.setOnClickListener(v -> {
            if (!isSquareRatio) {
                isSquareRatio = true;
                applyPreviewRatio();
                if (cameraProvider != null) bindCameraUseCases();
            }
        });

        wideRatioButton.setOnClickListener(v -> {
            if (isSquareRatio) {
                isSquareRatio = false;
                applyPreviewRatio();
                if (cameraProvider != null) bindCameraUseCases();
            }
        });

        com.google.android.material.button.MaterialButtonToggleGroup modeGroup = findViewById(R.id.modeContainer);
        View aiSubGroup = findViewById(R.id.aiSelectionContainer);
        modeGroup.addOnButtonCheckedListener((group, checkedId, isChecked) -> {
            if (isChecked) {
                isExpressionMode = (checkedId == R.id.btnModeExpression);
                aiSubGroup.setVisibility(isExpressionMode ? View.VISIBLE : View.GONE);
                if (isExpressionMode) {
                    Toast.makeText(this, "Chế độ AI: Hãy chọn kiểu detect!", Toast.LENGTH_SHORT).show();
                } else {
                    Toast.makeText(this, "Chế độ tự động: Đếm ngược 3 giây", Toast.LENGTH_SHORT).show();
                }
            }
        });

        com.google.android.material.button.MaterialButtonToggleGroup aiSubSelector = 
            (com.google.android.material.button.MaterialButtonToggleGroup) findViewById(R.id.aiSelectionContainer);

        // Đồng bộ trạng thái ban đầu theo nút đang được check trong XML (btnAiFace)
        isHandGestureMode = false;
        isFaceExpressionMode = true;

        aiSubSelector.addOnButtonCheckedListener((group, checkedId, isChecked) -> {
            if (!isChecked) return; // chỉ xử lý khi nút được chọn
            isHandGestureMode = (checkedId == R.id.btnAiHand);
            isFaceExpressionMode = (checkedId == R.id.btnAiFace);
            if (isFaceExpressionMode) {
                Toast.makeText(this, "Đã chuyển sang: Nhận diện khuôn mặt", Toast.LENGTH_SHORT).show();
            } else {
                Toast.makeText(this, "Đã chuyển sang: Nhận diện hành động", Toast.LENGTH_SHORT).show();
            }
        });

        applyPreviewRatio();

        View mainView = findViewById(R.id.main);
        if (mainView != null) {
            ViewCompat.setOnApplyWindowInsetsListener(mainView, (v, insets) -> {
                Insets systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars());
                v.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom);
                return insets;
            });
        }

        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
            startCamera();
        } else {
            requestCameraPermission();
        }
    }

    private void requestCameraPermission() {
        requestPermissions(new String[]{Manifest.permission.CAMERA}, CAMERA_PERMISSION_CODE);
    }

    private void startCamera() {
        ListenableFuture<ProcessCameraProvider> cameraProviderFuture = ProcessCameraProvider.getInstance(this);
        cameraProviderFuture.addListener(() -> {
            try {
                cameraProvider = cameraProviderFuture.get();
                bindCameraUseCases();
            } catch (ExecutionException | InterruptedException e) {
                Log.e(TAG, "Failed to start camera", e);
            }
        }, ContextCompat.getMainExecutor(this));
    }

    private void bindCameraUseCases() {
        if (cameraProvider == null) return;

        Preview preview = new Preview.Builder().build();
        imageCapture = buildImageCaptureUseCase();
        imageAnalysis = new ImageAnalysis.Builder()
                .setBackpressureStrategy(ImageAnalysis.STRATEGY_KEEP_ONLY_LATEST)
                .build();

        imageAnalysis.setAnalyzer(ContextCompat.getMainExecutor(this), imageProxy -> {
            boolean isWaiting = isWaitingForExpression;
            if (isHandGestureMode && gestureAnalyzer != null) {
                gestureAnalyzer.analyzeImageProxy(imageProxy, (gesture, box) -> {
                    // Luôn hiện khung xanh để test kể cả khi không trong mode capture
                    updateAiOverlay(box, gesture, android.graphics.Color.parseColor("#00E676"),
                            imageProxy.getWidth(), imageProxy.getHeight(),
                            imageProxy.getImageInfo().getRotationDegrees());
                    // Chỉ trigger nếu gesture nằm trong phần HIỂN THỊ của camera
                    if (isWaiting && targetExpression.equals(gesture)
                            && isBoxVisibleInPreview(box, imageProxy.getWidth(), imageProxy.getHeight(),
                                                    imageProxy.getImageInfo().getRotationDegrees())) {
                        triggerImmediateCapture();
                    }
                });
            } else if (isFaceExpressionMode && expressionAnalyzer != null) {
                expressionAnalyzer.analyzeImageProxy(imageProxy, (expression, faceBox) -> {
                    updateAiOverlay(faceBox, expression, android.graphics.Color.parseColor("#00B0FF"),
                            imageProxy.getWidth(), imageProxy.getHeight(),
                            imageProxy.getImageInfo().getRotationDegrees());
                    if (isWaiting && targetExpression.equals(expression)
                            && isBoxVisibleInPreview(faceBox, imageProxy.getWidth(), imageProxy.getHeight(),
                                                    imageProxy.getImageInfo().getRotationDegrees())) {
                        triggerImmediateCapture();
                    }
                });
            } else {
                imageProxy.close();
            }
        });

        preview.setSurfaceProvider(viewFinder.getSurfaceProvider());

        try {
            cameraProvider.unbindAll();
            camera = cameraProvider.bindToLifecycle(this, cameraSelector, preview, imageCapture, imageAnalysis);
            captureButton.setEnabled(true);
            applyFlashMode();
            updateFlashAvailability();
        } catch (Exception e) {
            Log.e(TAG, "Failed to bind camera use cases", e);
            captureButton.setEnabled(false);
            if (flashButton != null) flashButton.setEnabled(false);
            Toast.makeText(this, R.string.camera_not_ready, Toast.LENGTH_SHORT).show();
        }
    }

    private ImageCapture buildImageCaptureUseCase() {
        ImageCapture.Builder builder = new ImageCapture.Builder()
                .setCaptureMode(ImageCapture.CAPTURE_MODE_MINIMIZE_LATENCY);

        if (isSquareRatio) {
            builder.setTargetResolution(new Size(1080, 1080));
        } else {
            builder.setTargetAspectRatio(androidx.camera.core.AspectRatio.RATIO_16_9);
        }
        return builder.build();
    }

    private void applyPreviewRatio() {
        ConstraintLayout.LayoutParams params = (ConstraintLayout.LayoutParams) previewCard.getLayoutParams();
        params.dimensionRatio = isSquareRatio ? "1:1" : "16:9";
        previewCard.setLayoutParams(params);
    }

    private void startPhotoSequence() {
        if (isCapturingSequence) return;

        capturedCount = 0;
        savedImageUris.clear();
        cardLastCapture.setVisibility(View.GONE);
        isCapturingSequence = true;
        captureButton.setEnabled(false);
        squareRatioButton.setEnabled(false);
        wideRatioButton.setEnabled(false);
        findViewById(R.id.modeContainer).setEnabled(false);
        if (flashButton != null) flashButton.setEnabled(false);
        updateCaptureProgressUi();
        updateCaptureStatus(getString(R.string.capture_status_starting, maxPhotos));

        // Bắt đầu chuỗi chụp
        startCountdownAndCapture();
    }

    private void triggerImmediateCapture() {
        isWaitingForExpression = false;
        tvCountdown.post(() -> {
            if (aiOverlayView != null) aiOverlayView.updateOverlay(null, "");
            tvCountdown.setVisibility(View.GONE);
            takePhoto();
        });
    }

    private void updateAiOverlay(Rect box, String label, int color, int imgW, int imgH, int rotation) {
        if (aiOverlayView == null) return;
        aiOverlayView.post(() -> {
            java.util.List<Rect> boxes = new java.util.ArrayList<>();
            int viewW = aiOverlayView.getWidth();
            int viewH = aiOverlayView.getHeight();

            if (box != null && viewW > 0 && viewH > 0) {
                // Sau khi rotation, portrait device: imgW/imgH có thể được đảo
                float srcW = (rotation == 90 || rotation == 270) ? (float) imgH : (float) imgW;
                float srcH = (rotation == 90 || rotation == 270) ? (float) imgW : (float) imgH;

                // Tính CENTER_CROP: tìm scale để cả 2 chiều đều >= view (giống scaleType=centerCrop)
                float scaleX = viewW / srcW;
                float scaleY = viewH / srcH;
                float scale = Math.max(scaleX, scaleY); // CENTER_CROP lấy scale lớn nhất

                // Phần thừa bị crop ở giữa
                float cropOffsetX = (srcW * scale - viewW) / 2f;
                float cropOffsetY = (srcH * scale - viewH) / 2f;

                // Chuyển đổi: pixel ảnh -> pixel view (sau crop)
                int left   = (int)(box.left   * scale - cropOffsetX);
                int top    = (int)(box.top    * scale - cropOffsetY);
                int right  = (int)(box.right  * scale - cropOffsetX);
                int bottom = (int)(box.bottom * scale - cropOffsetY);

                // Mirror X cho camera trước
                if (cameraSelector == CameraSelector.DEFAULT_FRONT_CAMERA) {
                    int newLeft = viewW - right;
                    right = viewW - left;
                    left = newLeft;
                }

                // Clip vào phần hiển thị thực tế của overlay
                left   = Math.max(0, left);
                top    = Math.max(0, top);
                right  = Math.min(viewW, right);
                bottom = Math.min(viewH, bottom);

                // Chỉ vẽ nếu hộp hợp lệ
                if (left < right && top < bottom) {
                    boxes.add(new Rect(left, top, right, bottom));
                }
            }
            aiOverlayView.updateOverlay(boxes, label, color);
        });
    }

    // Overload for calls without images (e.g. clearing)
    private void updateAiOverlay(Rect box, String label) {
        updateAiOverlay(box, label, android.graphics.Color.parseColor("#00E676"), 640, 480, 90);
    }

    /**
     * Kiểm tra xem trung tâm bounding box có nằm trong phần hiển thị thực tế
     * (sau CENTER_CROP) của camera preview không.
     */
    private boolean isBoxVisibleInPreview(Rect box, int imgW, int imgH, int rotation) {
        if (box == null || aiOverlayView == null) return false;
        int viewW = aiOverlayView.getWidth();
        int viewH = aiOverlayView.getHeight();
        if (viewW <= 0 || viewH <= 0) return true; // biến mết thì cứ cho qua

        float srcW = (rotation == 90 || rotation == 270) ? (float) imgH : (float) imgW;
        float srcH = (rotation == 90 || rotation == 270) ? (float) imgW : (float) imgH;

        float scale = Math.max(viewW / srcW, viewH / srcH);
        float cropOffsetX = (srcW * scale - viewW) / 2f;
        float cropOffsetY = (srcH * scale - viewH) / 2f;

        // Tính trung tâm hộp sau transform
        float cx = ((box.left + box.right) / 2f) * scale - cropOffsetX;
        float cy = ((box.top + box.bottom) / 2f) * scale - cropOffsetY;

        // Mirror cho camera trước
        if (cameraSelector == CameraSelector.DEFAULT_FRONT_CAMERA) {
            cx = viewW - cx;
        }

        return cx >= 0 && cx <= viewW && cy >= 0 && cy <= viewH;
    }

    private void startCountdownAndCapture() {
        if (capturedCount >= maxPhotos) {
            isCapturingSequence = false;
            updateCaptureStatus(getString(R.string.capture_status_done, maxPhotos));
            findViewById(R.id.modeContainer).setEnabled(true);
            findViewById(R.id.aiSelectionContainer).setEnabled(true);
            goToSelectionPage();
            return;
        }

        tvCountdown.setVisibility(View.VISIBLE);
        int nextShot = capturedCount + 1;

        if (isExpressionMode) {
            if (isHandGestureMode) {
                if (nextShot % 2 != 0) {
                    targetExpression = "HI";
                    tvCountdown.setText("✌️");
                    updateCaptureStatus("Chụp " + nextShot + ": Giơ tay Hi nào!");
                } else {
                    targetExpression = "HEART";
                    tvCountdown.setText("❤️");
                    updateCaptureStatus("Chụp " + nextShot + ": Thả tim xem!");
                }
            } else {
                // Face mode
                if (nextShot % 2 != 0) {
                    targetExpression = "SMILE";
                    tvCountdown.setText(":D");
                    updateCaptureStatus("Chụp " + nextShot + ": Cười lên nào!");
                } else {
                    targetExpression = "WINK_RIGHT"; // Simple specific wink
                    tvCountdown.setText(";)");
                    updateCaptureStatus("Chụp " + nextShot + ": Nháy mắt cái nào!");
                }
            }

            // Lock indicator...
            new Handler(Looper.getMainLooper()).postDelayed(() -> {
                if (isCapturingSequence) {
                    isWaitingForExpression = true;
                    // Fallback 7s
                    new Handler(Looper.getMainLooper()).postDelayed(() -> {
                        if (isCapturingSequence && isWaitingForExpression) {
                            triggerImmediateCapture();
                        }
                    }, 7000);
                }
            }, 1000);
        } else {
            // Standard Countdown Mode
            runCountdown(3);
        }
    }

    private void runCountdown(int seconds) {
        if (seconds > 0) {
            tvCountdown.setText(String.valueOf(seconds));
            int nextShot = Math.min(capturedCount + 1, maxPhotos);
            updateCaptureStatus(getString(R.string.capture_status_countdown, nextShot, maxPhotos, seconds));
            new Handler(Looper.getMainLooper()).postDelayed(() -> {
                if (isCapturingSequence && !isExpressionMode) {
                    runCountdown(seconds - 1);
                }
            }, 1000);
        } else {
            tvCountdown.setVisibility(View.GONE);
            takePhoto();
        }
    }

    private void takePhoto() {
        if (imageCapture == null) {
            isCapturingSequence = false;
            captureButton.setEnabled(true);
            return;
        }

        File photoFile = new File(getExternalFilesDir(null), "photo_" + System.currentTimeMillis() + ".jpg");
        ImageCapture.OutputFileOptions outputOptions = new ImageCapture.OutputFileOptions.Builder(photoFile).build();

        Runnable performCapture = () -> imageCapture.takePicture(outputOptions, ContextCompat.getMainExecutor(this),
                new ImageCapture.OnImageSavedCallback() {
                    @Override
                    public void onImageSaved(@NonNull ImageCapture.OutputFileResults outputFileResults) {
                        capturedCount++;
                        Uri savedUri = Uri.fromFile(photoFile);
                        savedImageUris.add(savedUri);
                        showLastCapturePreview(savedUri);
                        if (!shouldUseScreenFlash()) {
                            playCaptureFlash();
                        }

                        // Phát âm thanh chụp hình
                        if (shutterSound != null && isSoundEnabled) {
                            shutterSound.play(MediaActionSound.SHUTTER_CLICK);
                        }

                        updateCaptureProgressUi();
                        updateCaptureStatus(getString(R.string.capture_status_captured, capturedCount, maxPhotos));

                        // Sau khi chụp xong 1 tấm, đợi 1 chút rồi đếm ngược cho tấm tiếp theo
                        new Handler(Looper.getMainLooper()).postDelayed(() -> startCountdownAndCapture(), 1000);
                    }

                    @Override
                    public void onError(@NonNull ImageCaptureException exception) {
                        isCapturingSequence = false;
                        isWaitingForExpression = false;
                        captureButton.setEnabled(true);
                        squareRatioButton.setEnabled(true);
                        wideRatioButton.setEnabled(true);
                        findViewById(R.id.modeContainer).setEnabled(true);
                        updateFlashAvailability();
                        updateCaptureStatus(getString(R.string.capture_status_error));
                        Toast.makeText(MainActivity.this, R.string.capture_failed, Toast.LENGTH_SHORT).show();
                    }
                });

        if (shouldUseScreenFlash()) {
            playScreenFlashThenCapture(performCapture);
        } else {
            performCapture.run();
        }
    }

    private void goToSelectionPage() {
        if (cameraProvider != null) cameraProvider.unbindAll();

        squareRatioButton.setEnabled(true);
        wideRatioButton.setEnabled(true);

        ArrayList<String> uriStrings = new ArrayList<>();
        for (Uri uri : savedImageUris) uriStrings.add(uri.toString());

        sessionState.setCapturedImageUris(uriStrings);
        sessionRepository.saveSession(sessionState);

        Intent intent = new Intent(MainActivity.this, PhotoSelectionActivity.class);
        intent.putStringArrayListExtra(IntentKeys.EXTRA_CAPTURED_IMAGES, uriStrings);
        startActivity(intent);
        finish();
    }

    private void initCaptureUi() {
        captureProgress.setMax(Math.max(maxPhotos, 1));
        captureProgress.setProgress(0);
        dotContainer.removeAllViews();
        for (int i = 0; i < maxPhotos; i++) {
            View dot = new View(this);
            LinearLayout.LayoutParams params = new LinearLayout.LayoutParams(dpToPx(10), dpToPx(10));
            params.setMargins(dpToPx(4), 0, dpToPx(4), 0);
            params.gravity = Gravity.CENTER_VERTICAL;
            dot.setLayoutParams(params);
            dot.setBackgroundResource(R.drawable.bg_capture_dot_inactive);
            dotContainer.addView(dot);
        }
        updateCaptureStatus(getString(R.string.capture_status_ready));
    }

    private void updateCaptureProgressUi() {
        captureProgress.setProgressCompat(capturedCount, true);
        for (int i = 0; i < dotContainer.getChildCount(); i++) {
            View dot = dotContainer.getChildAt(i);
            dot.setBackgroundResource(i < capturedCount ? R.drawable.bg_capture_dot_active : R.drawable.bg_capture_dot_inactive);
        }
    }

    private void updateCaptureStatus(String message) {
        tvCaptureStatus.setText(message);
    }

    private void showLastCapturePreview(Uri uri) {
        cardLastCapture.setVisibility(View.VISIBLE);
        Glide.with(this)
                .load(uri)
                .centerCrop()
                .into(ivLastCapturePreview);
    }

    private void playCaptureFlash() {
        captureFlashOverlay.setVisibility(View.VISIBLE);
        captureFlashOverlay.setAlpha(0.6f);
        captureFlashOverlay.animate()
                .alpha(0f)
                .setDuration(220)
                .withEndAction(() -> captureFlashOverlay.setVisibility(View.GONE))
                .start();
    }

    private void toggleFlash() {
        if (camera == null || imageCapture == null) {
            Toast.makeText(this, R.string.camera_not_ready, Toast.LENGTH_SHORT).show();
            return;
        }
        isFlashPreferredOn = !isFlashPreferredOn;
        sessionState.setFlashEnabled(isFlashPreferredOn);
        sessionRepository.saveSession(sessionState);
        applyFlashMode();
        updateFlashAvailability();
        Toast.makeText(this, isFlashPreferredOn ? R.string.camera_flash_on : R.string.camera_flash_off, Toast.LENGTH_SHORT).show();
    }

    private void toggleScreenFlashStrength() {
        isScreenFlashStrong = !isScreenFlashStrong;
        sessionState.setScreenFlashStrong(isScreenFlashStrong);
        sessionRepository.saveSession(sessionState);
        int levelRes = isScreenFlashStrong ? R.string.camera_screen_flash_level_strong : R.string.camera_screen_flash_level_normal;
        Toast.makeText(this, getString(R.string.camera_screen_flash_level_changed, getString(levelRes)), Toast.LENGTH_SHORT).show();
    }

    private void applyFlashMode() {
        if (imageCapture == null) return;
        imageCapture.setFlashMode(shouldUseHardwareFlash() ? ImageCapture.FLASH_MODE_ON : ImageCapture.FLASH_MODE_OFF);
    }

    private void updateFlashAvailability() {
        if (flashButton == null) return;

        boolean canToggleFlash = camera != null && !isCapturingSequence;
        flashButton.setEnabled(canToggleFlash);
        flashButton.setAlpha(canToggleFlash ? 1f : 0.35f);
        flashButton.setImageResource(isFlashPreferredOn ? R.drawable.ic_flash_on_24 : R.drawable.ic_flash_off_24);
    }

    private void toggleSound() {
        isSoundEnabled = !isSoundEnabled;
        sessionState.setSoundEnabled(isSoundEnabled);
        sessionRepository.saveSession(sessionState);
        updateSoundIcon();
        Toast.makeText(this, isSoundEnabled ? "Đã bật âm thanh" : "Đã tắt âm thanh", Toast.LENGTH_SHORT).show();
    }

    private void updateSoundIcon() {
        if (soundButton != null) {
            soundButton.setImageResource(isSoundEnabled ? R.drawable.ic_sound_on : R.drawable.ic_sound_off);
        }
    }

    private boolean shouldUseHardwareFlash() {
        return isFlashPreferredOn
                && camera != null
                && camera.getCameraInfo().hasFlashUnit()
                && cameraSelector == CameraSelector.DEFAULT_BACK_CAMERA;
    }

    private boolean shouldUseScreenFlash() {
        return isFlashPreferredOn && cameraSelector == CameraSelector.DEFAULT_FRONT_CAMERA;
    }

    private void playScreenFlashThenCapture(Runnable onFlashPeak) {
        float flashPeakAlpha = isScreenFlashStrong ? 1.0f : 0.86f;
        long fadeInDuration = isScreenFlashStrong ? 110L : 90L;
        long fadeOutDuration = isScreenFlashStrong ? 220L : 170L;

        captureFlashOverlay.setVisibility(View.VISIBLE);
        captureFlashOverlay.setAlpha(0f);
        captureFlashOverlay.animate()
                .alpha(flashPeakAlpha)
                .setDuration(fadeInDuration)
                .withEndAction(() -> {
                    onFlashPeak.run();
                    captureFlashOverlay.animate()
                            .alpha(0f)
                            .setDuration(fadeOutDuration)
                            .withEndAction(() -> captureFlashOverlay.setVisibility(View.GONE))
                            .start();
                })
                .start();
    }

    private int dpToPx(int dp) {
        return Math.round(dp * getResources().getDisplayMetrics().density);
    }

    private void setupToolbar() {
        MaterialToolbar toolbar = findViewById(R.id.topAppBar);
        setSupportActionBar(toolbar);
        if (getSupportActionBar() != null) {
            getSupportActionBar().setDisplayHomeAsUpEnabled(true);
            getSupportActionBar().setDisplayShowTitleEnabled(false);
        }
        toolbar.setNavigationIcon(R.drawable.ic_arrow_back_24);
        toolbar.setNavigationOnClickListener(v -> getOnBackPressedDispatcher().onBackPressed());
    }

    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions, @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        if (requestCode == CAMERA_PERMISSION_CODE && grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
            startCamera();
        } else if (requestCode == CAMERA_PERMISSION_CODE) {
            Toast.makeText(this, R.string.camera_permission_required, Toast.LENGTH_SHORT).show();
        }
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (cameraProvider != null) {
            cameraProvider.unbindAll();
        }
        if (shutterSound != null) {
            shutterSound.release();
        }
    }
}

package com.example.expressionphotobooth;

import android.net.Uri;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import com.bumptech.glide.Glide;
import com.bumptech.glide.load.engine.DiskCacheStrategy;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;

public class PhotoAdapter extends RecyclerView.Adapter<PhotoAdapter.PhotoViewHolder> {
    public interface OnPhotoSelectedListener {
        void onSelectionChanged(List<Uri> selectedUris, int selectedCount);
    }

    private final List<Uri> uris;
    private final OnPhotoSelectedListener onPhotoSelectedListener;
    private final Set<Integer> selectedPositions = new LinkedHashSet<>();

    public PhotoAdapter(List<Uri> uris, OnPhotoSelectedListener onPhotoSelectedListener) {
        this.uris = new ArrayList<>(uris);
        this.onPhotoSelectedListener = onPhotoSelectedListener;
    }

    @NonNull
    @Override
    public PhotoViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        return new PhotoViewHolder(LayoutInflater.from(parent.getContext()).inflate(R.layout.item_photo, parent, false));
    }

    @Override
    public void onBindViewHolder(@NonNull PhotoViewHolder holder, int position) {
        Uri uri = uris.get(position);
        // Glide handles file/content URI decoding better than setImageURI in RecyclerView.
        Glide.with(holder.imageView)
                .load(uri)
                .diskCacheStrategy(DiskCacheStrategy.AUTOMATIC)
                .placeholder(android.R.color.darker_gray)
                .error(android.R.drawable.ic_menu_report_image)
                .into(holder.imageView);
        holder.tvIndex.setText(String.valueOf(position + 1));

        boolean isSelected = selectedPositions.contains(position);
        holder.selectionOverlay.setAlpha(isSelected ? 1f : 0f);
        if (holder.cvSelectedBadge != null) {
            holder.cvSelectedBadge.setVisibility(isSelected ? View.VISIBLE : View.GONE);
        }

        holder.itemView.setOnClickListener(v -> {
            int current = holder.getBindingAdapterPosition();
            if (current == RecyclerView.NO_POSITION) {
                return;
            }

            if (selectedPositions.contains(current)) {
                selectedPositions.remove(current);
            } else {
                selectedPositions.add(current);
            }
            notifyItemChanged(current);

            if (onPhotoSelectedListener != null) {
                List<Uri> selectedUris = getSelectedUris();
                onPhotoSelectedListener.onSelectionChanged(selectedUris, selectedUris.size());
            }
        });
    }

    @Override
    public int getItemCount() {
        return uris.size();
    }

    public Uri getSelectedUri() {
        List<Uri> selectedUris = getSelectedUris();
        return selectedUris.isEmpty() ? null : selectedUris.get(0);
    }

    public List<Uri> getSelectedUris() {
        List<Uri> result = new ArrayList<>();
        for (Integer selectedPosition : selectedPositions) {
            if (selectedPosition != null && selectedPosition >= 0 && selectedPosition < uris.size()) {
                result.add(uris.get(selectedPosition));
            }
        }
        return result;
    }

    public void setUris(List<Uri> newUris) {
        Set<String> keepSelected = new HashSet<>();
        for (Uri selected : getSelectedUris()) {
            keepSelected.add(selected.toString());
        }

        uris.clear();
        uris.addAll(newUris);
        selectedPositions.clear();

        for (int i = 0; i < uris.size(); i++) {
            if (keepSelected.contains(uris.get(i).toString())) {
                selectedPositions.add(i);
            }
        }
        notifyDataSetChanged();
    }

    public void clearSelection() {
        if (selectedPositions.isEmpty()) {
            return;
        }
        selectedPositions.clear();
        notifyDataSetChanged();
    }

    public static final class PhotoViewHolder extends RecyclerView.ViewHolder {
        final ImageView imageView;
        final View selectionOverlay;
        final View cvSelectedBadge;
        final TextView tvIndex;

        public PhotoViewHolder(View itemView) {
            super(itemView);
            imageView = itemView.findViewById(R.id.ivPhoto);
            selectionOverlay = itemView.findViewById(R.id.selectionOverlay);
            cvSelectedBadge = itemView.findViewById(R.id.cvSelectedBadge);
            tvIndex = itemView.findViewById(R.id.tvIndex);
        }
    }
}

package com.example.expressionphotobooth;

import android.net.Uri;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import com.bumptech.glide.Glide;
import com.bumptech.glide.load.engine.DiskCacheStrategy;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;

public class PhotoAdapter extends RecyclerView.Adapter<PhotoAdapter.PhotoViewHolder> {
    public interface OnPhotoSelectedListener {
        void onSelectionChanged(List<Uri> selectedUris, int selectedCount);
    }

    private final List<Uri> uris;
    private final OnPhotoSelectedListener onPhotoSelectedListener;
    private final int maxSelection;
    private final Set<Integer> selectedPositions = new LinkedHashSet<>();

    public PhotoAdapter(List<Uri> uris, OnPhotoSelectedListener onPhotoSelectedListener) {
        this(uris, Integer.MAX_VALUE, onPhotoSelectedListener);
    }

    public PhotoAdapter(List<Uri> uris, int maxSelection, OnPhotoSelectedListener onPhotoSelectedListener) {
        this.uris = new ArrayList<>(uris);
        this.maxSelection = Math.max(1, maxSelection);
        this.onPhotoSelectedListener = onPhotoSelectedListener;
    }

    @NonNull
    @Override
    public PhotoViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        return new PhotoViewHolder(LayoutInflater.from(parent.getContext()).inflate(R.layout.item_photo, parent, false));
    }

    @Override
    public void onBindViewHolder(@NonNull PhotoViewHolder holder, int position) {
        Uri uri = uris.get(position);
        // Glide handles file/content URI decoding better than setImageURI in RecyclerView.
        Glide.with(holder.imageView)
                .load(uri)
                .diskCacheStrategy(DiskCacheStrategy.AUTOMATIC)
                .placeholder(android.R.color.darker_gray)
                .error(android.R.drawable.ic_menu_report_image)
                .into(holder.imageView);
        holder.tvIndex.setText(String.valueOf(position + 1));

        boolean isSelected = selectedPositions.contains(position);
        holder.selectionOverlay.setAlpha(isSelected ? 1f : 0f);
        if (holder.cvSelectedBadge != null) {
            holder.cvSelectedBadge.setVisibility(isSelected ? View.VISIBLE : View.GONE);
        }

        holder.itemView.setOnClickListener(v -> {
            int current = holder.getBindingAdapterPosition();
            if (current == RecyclerView.NO_POSITION) {
                return;
            }

            if (selectedPositions.contains(current)) {
                selectedPositions.remove(current);
            } else {
                if (selectedPositions.size() >= maxSelection) {
                    Toast.makeText(v.getContext(), v.getContext().getString(R.string.selection_limit_reached, maxSelection), Toast.LENGTH_SHORT).show();
                    return;
                }
                selectedPositions.add(current);
            }
            notifyItemChanged(current);

            if (onPhotoSelectedListener != null) {
                List<Uri> selectedUris = getSelectedUris();
                onPhotoSelectedListener.onSelectionChanged(selectedUris, selectedUris.size());
            }
        });
    }

    @Override
    public int getItemCount() {
        return uris.size();
    }

    public Uri getSelectedUri() {
        List<Uri> selectedUris = getSelectedUris();
        return selectedUris.isEmpty() ? null : selectedUris.get(0);
    }

    public List<Uri> getSelectedUris() {
        List<Uri> result = new ArrayList<>();
        for (Integer selectedPosition : selectedPositions) {
            if (selectedPosition != null && selectedPosition >= 0 && selectedPosition < uris.size()) {
                result.add(uris.get(selectedPosition));
            }
        }
        return result;
    }

    public void setUris(List<Uri> newUris) {
        Set<String> keepSelected = new HashSet<>();
        for (Uri selected : getSelectedUris()) {
            keepSelected.add(selected.toString());
        }

        uris.clear();
        uris.addAll(newUris);
        selectedPositions.clear();

        for (int i = 0; i < uris.size(); i++) {
            if (keepSelected.contains(uris.get(i).toString())) {
                selectedPositions.add(i);
            }
        }
        notifyDataSetChanged();
    }

    public void clearSelection() {
        if (selectedPositions.isEmpty()) {
            return;
        }
        selectedPositions.clear();
        notifyDataSetChanged();
    }

    public static final class PhotoViewHolder extends RecyclerView.ViewHolder {
        final ImageView imageView;
        final View selectionOverlay;
        final View cvSelectedBadge;
        final TextView tvIndex;

        public PhotoViewHolder(View itemView) {
            super(itemView);
            imageView = itemView.findViewById(R.id.ivPhoto);
            selectionOverlay = itemView.findViewById(R.id.selectionOverlay);
            cvSelectedBadge = itemView.findViewById(R.id.cvSelectedBadge);
            tvIndex = itemView.findViewById(R.id.tvIndex);
        }
    }
}

package com.example.expressionphotobooth;

import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.widget.TextView;
import android.widget.Toast;

import androidx.activity.result.ActivityResultLauncher;
import androidx.activity.result.contract.ActivityResultContracts;
import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.expressionphotobooth.domain.model.SessionState;
import com.example.expressionphotobooth.domain.repository.SessionRepository;
import com.google.android.material.appbar.MaterialToolbar;
import com.google.android.material.button.MaterialButton;

import java.util.ArrayList;
import java.util.ArrayDeque;
import java.util.LinkedHashSet;
import java.util.List;

public class PhotoSelectionActivity extends AppCompatActivity {
    private PhotoAdapter adapter;
    private SessionRepository sessionRepository;
    private SessionState sessionState;
    private MaterialButton btnContinueToEdit;
    private MaterialButton btnDirectToResult;
    private TextView tvSelectionStatus;
    private TextView tvClearSelection;
    private SelectedPhotoPreviewAdapter selectedPhotoPreviewAdapter;
    private final ArrayDeque<String> pendingEditOriginalUris = new ArrayDeque<>();
    private boolean isBatchEditing = false;

    private final ActivityResultLauncher<Intent> editActivityResultLauncher = registerForActivityResult(
            new ActivityResultContracts.StartActivityForResult(),
            result -> {
                boolean editSaved = false;
                if (result.getResultCode() == Activity.RESULT_OK && result.getData() != null) {
                    String originalUri = result.getData().getStringExtra(IntentKeys.EXTRA_ORIGINAL_URI);
                    String editedUri = result.getData().getStringExtra(IntentKeys.EXTRA_EDITED_URI);
                    if (originalUri != null && editedUri != null) {
                        sessionState.getEditedImageUris().put(originalUri, editedUri);
                        sessionRepository.saveSession(sessionState);
                        editSaved = true;
                    }
                }

                if (isBatchEditing && !editSaved) {
                    // User backed out/canceled; stop queue gracefully without false success toast.
                    isBatchEditing = false;
                    pendingEditOriginalUris.clear();
                    updateAdapterUris();
                    Toast.makeText(this, R.string.batch_edit_cancelled, Toast.LENGTH_SHORT).show();
                    return;
                }

                if (isBatchEditing && !pendingEditOriginalUris.isEmpty()) {
                    launchNextEditInQueue();
                } else {
                    isBatchEditing = false;
                    pendingEditOriginalUris.clear();
                    updateAdapterUris();
                    if (adapter != null) {
                        adapter.clearSelection();
                    }
                    updateSelectionStatus(0);
                    updateSelectedPreviewStrip(new ArrayList<>());
                    btnContinueToEdit.setEnabled(false);
                    btnContinueToEdit.setText(R.string.btn_edit);
                    if (editSaved) {
                        Toast.makeText(this, R.string.batch_edit_completed, Toast.LENGTH_SHORT).show();
                    }
                }
            }
    );

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_photo_selection);
        sessionRepository = ((AppContainer) getApplication()).getSessionRepository();
        sessionState = sessionRepository.getSession();
        setupToolbar();

        RecyclerView rvPhotos = findViewById(R.id.rvPhotos);
        btnContinueToEdit = findViewById(R.id.btnNextToEdit);
        btnDirectToResult = findViewById(R.id.btnDirectToResult);
        tvSelectionStatus = findViewById(R.id.tvSelectionStatus);
        tvClearSelection = findViewById(R.id.tvClearSelection);
        RecyclerView rvSelectedPhotos = findViewById(R.id.rvSelectedPhotos);

        selectedPhotoPreviewAdapter = new SelectedPhotoPreviewAdapter();
        rvSelectedPhotos.setLayoutManager(new LinearLayoutManager(this, RecyclerView.HORIZONTAL, false));
        rvSelectedPhotos.setAdapter(selectedPhotoPreviewAdapter);

        btnContinueToEdit.setEnabled(false);
        btnDirectToResult.setEnabled(false);

        ArrayList<String> imageUriStrings = getIntent().getStringArrayListExtra(IntentKeys.EXTRA_CAPTURED_IMAGES);
        if (imageUriStrings != null && !imageUriStrings.isEmpty()) {
            sessionState.setCapturedImageUris(imageUriStrings);
            sessionRepository.saveSession(sessionState);
        }

        rvPhotos.setLayoutManager(new GridLayoutManager(this, 2));
        rvPhotos.setHasFixedSize(true);

        adapter = new PhotoAdapter(new ArrayList<>(), (selectedUris, selectedCount) -> {
            btnContinueToEdit.setEnabled(selectedCount > 0);
            updateSelectionStatus(selectedCount);
            updateResultButtonState(selectedCount);
            updateSelectedPreviewStrip(selectedUris);
            tvClearSelection.setEnabled(selectedCount > 0);
            tvClearSelection.setAlpha(selectedCount > 0 ? 1f : 0.45f);
        });
        rvPhotos.setAdapter(adapter);
        updateAdapterUris();

        tvClearSelection.setOnClickListener(v -> {
            if (adapter == null) {
                return;
            }
            adapter.clearSelection();
            updateSelectionStatus(0);
            updateSelectedPreviewStrip(new ArrayList<>());
            btnContinueToEdit.setEnabled(false);
            btnContinueToEdit.setText(R.string.btn_edit);
            updateResultButtonState(0);
            tvClearSelection.setEnabled(false);
            tvClearSelection.setAlpha(0.45f);
        });
        tvClearSelection.setEnabled(false);
        tvClearSelection.setAlpha(0.45f);

        btnContinueToEdit.setOnClickListener(v -> {
            List<Uri> selectedDisplayUris = adapter.getSelectedUris();
            if (selectedDisplayUris.isEmpty()) {
                return;
            }

            pendingEditOriginalUris.clear();
            for (Uri selectedDisplayUri : selectedDisplayUris) {
                Uri originalUri = getSelectedOriginalUri(selectedDisplayUri);
                if (originalUri != null) {
                    pendingEditOriginalUris.add(originalUri.toString());
                }
            }

            if (pendingEditOriginalUris.isEmpty()) {
                return;
            }

            isBatchEditing = true;
            if (pendingEditOriginalUris.size() > 1) {
                Toast.makeText(this, getString(R.string.batch_edit_start, pendingEditOriginalUris.size()), Toast.LENGTH_SHORT).show();
            }
            launchNextEditInQueue();
        });

        btnDirectToResult.setOnClickListener(v -> {
            List<Uri> selectedDisplayUris = adapter.getSelectedUris();
            if (selectedDisplayUris.isEmpty()) {
                Toast.makeText(this, "Vui lòng chọn ít nhất 1 ảnh để tiếp tục.", Toast.LENGTH_SHORT).show();
                return;
            }

            LinkedHashSet<String> selectedOriginalUris = new LinkedHashSet<>();
            for (Uri selectedDisplayUri : selectedDisplayUris) {
                Uri originalUri = getSelectedOriginalUri(selectedDisplayUri);
                if (originalUri != null) {
                    selectedOriginalUris.add(originalUri.toString());
                }
            }

            if (selectedOriginalUris.isEmpty()) {
                Toast.makeText(this, "Vui lòng chọn ít nhất 1 ảnh để tiếp tục.", Toast.LENGTH_SHORT).show();
                return;
            }

            // Chi lay nhom da chon de tao ket qua cuoi.
            ArrayList<String> finalImagesToStitch = new ArrayList<>();

            for (String originalUriStr : selectedOriginalUris) {
                String editedUriStr = sessionState.getEditedImageUris().get(originalUriStr);
                finalImagesToStitch.add(editedUriStr != null ? editedUriStr : originalUriStr);
            }

            if (finalImagesToStitch.isEmpty()) return;

            Intent intent = new Intent(PhotoSelectionActivity.this, ResultActivity.class);
            intent.putStringArrayListExtra(IntentKeys.EXTRA_CAPTURED_IMAGES, finalImagesToStitch);

            startActivity(intent);
        });
    }

    private void updateAdapterUris() {
        List<Uri> displayUris = new ArrayList<>();
        for (String originalUriStr : sessionState.getCapturedImageUris()) {
            String editedUriStr = sessionState.getEditedImageUris().get(originalUriStr);
            displayUris.add(Uri.parse(editedUriStr != null ? editedUriStr : originalUriStr));
        }

        if (adapter != null) {
            adapter.setUris(displayUris);
        }
        btnContinueToEdit.setEnabled(false);
        updateSelectionStatus(0);
        updateResultButtonState(0);
        updateSelectedPreviewStrip(new ArrayList<>());
    }

    private void updateSelectionStatus(int selectedCount) {
        int required = getRequiredSelectionCount();
        if (selectedCount <= 0) {
            tvSelectionStatus.setText(getString(R.string.selection_status_none, required));
            btnContinueToEdit.setText(R.string.btn_edit);
        } else {
            tvSelectionStatus.setText(getString(R.string.selection_status_selected, selectedCount, required));
            btnContinueToEdit.setText(getString(R.string.btn_edit_with_count, selectedCount));
        }
    }

    private void updateResultButtonState(int selectedCount) {
        int required = getRequiredSelectionCount();
        boolean canExport = selectedCount > 0;
        btnDirectToResult.setEnabled(canExport);
        btnDirectToResult.setText(getString(R.string.btn_result_with_count, selectedCount, required));
    }

    private int getRequiredSelectionCount() {
        int capturedCount = sessionState.getCapturedImageUris().size();
        if (capturedCount <= 0) {
            return 0;
        }
        int configuredCount = sessionState.getPhotoCount();
        return configuredCount > 0 ? Math.min(configuredCount, capturedCount) : capturedCount;
    }

    private Uri getSelectedOriginalUri(Uri currentDisplayUri) {
        if (currentDisplayUri == null) {
            return null;
        }

        List<String> captured = sessionState.getCapturedImageUris();
        for (int i = 0; i < captured.size(); i++) {
            String orig = captured.get(i);
            String edit = sessionState.getEditedImageUris().get(orig);
            if (currentDisplayUri.toString().equals(orig) || currentDisplayUri.toString().equals(edit)) {
                return Uri.parse(orig);
            }
        }
        return null;
    }

    private void launchNextEditInQueue() {
        String nextOriginalUri = pendingEditOriginalUris.pollFirst();
        if (nextOriginalUri == null) {
            isBatchEditing = false;
            updateAdapterUris();
            return;
        }

        sessionState.setSelectedImageUri(nextOriginalUri);
        sessionRepository.saveSession(sessionState);

        Intent intent = new Intent(PhotoSelectionActivity.this, EditPhotoActivity.class);
        intent.putExtra(IntentKeys.EXTRA_SELECTED_IMAGE, nextOriginalUri);
        editActivityResultLauncher.launch(intent);
    }

    private void updateSelectedPreviewStrip(List<Uri> selectedUris) {
        selectedPhotoPreviewAdapter.setSelectedUris(selectedUris);
    }

    private void setupToolbar() {
        MaterialToolbar toolbar = findViewById(R.id.topAppBar);
        setSupportActionBar(toolbar);
        if (getSupportActionBar() != null) {
            getSupportActionBar().setDisplayHomeAsUpEnabled(true);
        }
        toolbar.setNavigationIcon(R.drawable.ic_arrow_back_24);
        toolbar.setNavigationOnClickListener(v -> getOnBackPressedDispatcher().onBackPressed());
    }

    @Override
    public boolean onSupportNavigateUp() {
        getOnBackPressedDispatcher().onBackPressed();
        return true;
    }
}

package com.example.expressionphotobooth;

import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.widget.TextView;
import android.widget.Toast;

import androidx.activity.result.ActivityResultLauncher;
import androidx.activity.result.contract.ActivityResultContracts;
import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.expressionphotobooth.domain.model.SessionState;
import com.example.expressionphotobooth.domain.repository.SessionRepository;
import com.google.android.material.appbar.MaterialToolbar;
import com.google.android.material.button.MaterialButton;

import java.util.ArrayList;
import java.util.ArrayDeque;
import java.util.Arrays;
import java.util.LinkedHashSet;
import java.util.List;

public class PhotoSelectionActivity extends AppCompatActivity {
    private static final int REQUIRED_SELECTION_COUNT = 4;
    private PhotoAdapter adapter;
    private SessionRepository sessionRepository;
    private SessionState sessionState;
    private MaterialButton btnContinueToEdit;
    private MaterialButton btnDirectToResult;
    private TextView tvSelectionStatus;
    private TextView tvClearSelection;
    private SelectedPhotoPreviewAdapter selectedPhotoPreviewAdapter;
    private final ArrayDeque<String> pendingEditOriginalUris = new ArrayDeque<>();
    private boolean isBatchEditing = false;

    private final ActivityResultLauncher<Intent> editActivityResultLauncher = registerForActivityResult(
            new ActivityResultContracts.StartActivityForResult(),
            result -> {
                boolean editSaved = false;
                if (result.getResultCode() == Activity.RESULT_OK && result.getData() != null) {
                    String originalUri = result.getData().getStringExtra(IntentKeys.EXTRA_ORIGINAL_URI);
                    String editedUri = result.getData().getStringExtra(IntentKeys.EXTRA_EDITED_URI);
                    if (originalUri != null && editedUri != null) {
                        sessionState.getEditedImageUris().put(originalUri, editedUri);
                        sessionRepository.saveSession(sessionState);
                        editSaved = true;
                    }
                }

                if (isBatchEditing && !editSaved) {
                    // User backed out/canceled; stop queue gracefully without false success toast.
                    isBatchEditing = false;
                    pendingEditOriginalUris.clear();
                    updateAdapterUris();
                    Toast.makeText(this, R.string.batch_edit_cancelled, Toast.LENGTH_SHORT).show();
                    return;
                }

                if (isBatchEditing && !pendingEditOriginalUris.isEmpty()) {
                    launchNextEditInQueue();
                } else {
                    isBatchEditing = false;
                    pendingEditOriginalUris.clear();
                    updateAdapterUris();
                    if (adapter != null) {
                        adapter.clearSelection();
                    }
                    updateSelectionStatus(0);
                    updateSelectedPreviewStrip(new ArrayList<>());
                    btnContinueToEdit.setEnabled(false);
                    btnContinueToEdit.setText(R.string.btn_edit);
                    if (editSaved) {
                        Toast.makeText(this, R.string.batch_edit_completed, Toast.LENGTH_SHORT).show();
                    }
                }
            }
    );

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_photo_selection);
        sessionRepository = ((AppContainer) getApplication()).getSessionRepository();
        sessionState = sessionRepository.getSession();
        setupToolbar();

        RecyclerView rvPhotos = findViewById(R.id.rvPhotos);
        btnContinueToEdit = findViewById(R.id.btnNextToEdit);
        btnDirectToResult = findViewById(R.id.btnDirectToResult);
        MaterialButton btnHelpSelection = findViewById(R.id.btnHelpSelection);
        tvSelectionStatus = findViewById(R.id.tvSelectionStatus);
        tvClearSelection = findViewById(R.id.tvClearSelection);
        RecyclerView rvSelectedPhotos = findViewById(R.id.rvSelectedPhotos);
        btnHelpSelection.setOnClickListener(v -> showSelectionHelpDialog());

        selectedPhotoPreviewAdapter = new SelectedPhotoPreviewAdapter();
        rvSelectedPhotos.setLayoutManager(new LinearLayoutManager(this, RecyclerView.HORIZONTAL, false));
        rvSelectedPhotos.setAdapter(selectedPhotoPreviewAdapter);

        btnContinueToEdit.setEnabled(false);
        btnDirectToResult.setEnabled(false);

        ArrayList<String> imageUriStrings = getIntent().getStringArrayListExtra(IntentKeys.EXTRA_CAPTURED_IMAGES);
        if (imageUriStrings != null && !imageUriStrings.isEmpty()) {
            sessionState.setCapturedImageUris(imageUriStrings);
            sessionRepository.saveSession(sessionState);
        }

        rvPhotos.setLayoutManager(new GridLayoutManager(this, 2));
        rvPhotos.setHasFixedSize(true);

        adapter = new PhotoAdapter(new ArrayList<>(), REQUIRED_SELECTION_COUNT, (selectedUris, selectedCount) -> {
            btnContinueToEdit.setEnabled(selectedCount > 0);
            updateSelectionStatus(selectedCount);
            updateResultButtonState(selectedCount);
            updateSelectedPreviewStrip(selectedUris);
            tvClearSelection.setEnabled(selectedCount > 0);
            tvClearSelection.setAlpha(selectedCount > 0 ? 1f : 0.45f);
        });
        rvPhotos.setAdapter(adapter);
        updateAdapterUris();

        tvClearSelection.setOnClickListener(v -> {
            if (adapter == null) {
                return;
            }
            adapter.clearSelection();
            updateSelectionStatus(0);
            updateSelectedPreviewStrip(new ArrayList<>());
            btnContinueToEdit.setEnabled(false);
            btnContinueToEdit.setText(R.string.btn_edit);
            updateResultButtonState(0);
            tvClearSelection.setEnabled(false);
            tvClearSelection.setAlpha(0.45f);
        });
        tvClearSelection.setEnabled(false);
        tvClearSelection.setAlpha(0.45f);

        btnContinueToEdit.setOnClickListener(v -> {
            List<Uri> selectedDisplayUris = adapter.getSelectedUris();
            if (selectedDisplayUris.isEmpty()) {
                return;
            }

            pendingEditOriginalUris.clear();
            for (Uri selectedDisplayUri : selectedDisplayUris) {
                Uri originalUri = getSelectedOriginalUri(selectedDisplayUri);
                if (originalUri != null) {
                    pendingEditOriginalUris.add(originalUri.toString());
                }
            }

            if (pendingEditOriginalUris.isEmpty()) {
                return;
            }

            isBatchEditing = true;
            if (pendingEditOriginalUris.size() > 1) {
                Toast.makeText(this, getString(R.string.batch_edit_start, pendingEditOriginalUris.size()), Toast.LENGTH_SHORT).show();
            }
            launchNextEditInQueue();
        });

        btnDirectToResult.setOnClickListener(v -> {
            List<Uri> selectedDisplayUris = adapter.getSelectedUris();
            int required = getRequiredSelectionCount();
            if (selectedDisplayUris.size() != required) {
                Toast.makeText(this, getString(R.string.select_enough_for_result, required), Toast.LENGTH_SHORT).show();
                return;
            }

            LinkedHashSet<String> selectedOriginalUris = new LinkedHashSet<>();
            for (Uri selectedDisplayUri : selectedDisplayUris) {
                Uri originalUri = getSelectedOriginalUri(selectedDisplayUri);
                if (originalUri != null) {
                    selectedOriginalUris.add(originalUri.toString());
                }
            }

            if (selectedOriginalUris.size() != required) {
                Toast.makeText(this, getString(R.string.select_enough_for_result, required), Toast.LENGTH_SHORT).show();
                return;
            }

            // Chi lay nhom da chon de tao ket qua cuoi.
            ArrayList<String> finalImagesToStitch = new ArrayList<>();

            for (String originalUriStr : selectedOriginalUris) {
                String editedUriStr = sessionState.getEditedImageUris().get(originalUriStr);
                finalImagesToStitch.add(editedUriStr != null ? editedUriStr : originalUriStr);
            }

            if (finalImagesToStitch.isEmpty()) return;

            Intent intent = new Intent(PhotoSelectionActivity.this, ResultActivity.class);
            intent.putStringArrayListExtra(IntentKeys.EXTRA_CAPTURED_IMAGES, finalImagesToStitch);

            startActivity(intent);
        });
    }

    private void updateAdapterUris() {
        List<Uri> displayUris = new ArrayList<>();
        for (String originalUriStr : sessionState.getCapturedImageUris()) {
            String editedUriStr = sessionState.getEditedImageUris().get(originalUriStr);
            displayUris.add(Uri.parse(editedUriStr != null ? editedUriStr : originalUriStr));
        }

        if (adapter != null) {
            adapter.setUris(displayUris);
        }
        btnContinueToEdit.setEnabled(false);
        updateSelectionStatus(0);
        updateResultButtonState(0);
        updateSelectedPreviewStrip(new ArrayList<>());
    }

    private void updateSelectionStatus(int selectedCount) {
        int required = getRequiredSelectionCount();
        if (selectedCount <= 0) {
            tvSelectionStatus.setText(getString(R.string.selection_status_none, required));
            btnContinueToEdit.setText(R.string.btn_edit);
        } else {
            tvSelectionStatus.setText(getString(R.string.selection_status_selected, selectedCount, required));
            btnContinueToEdit.setText(getString(R.string.btn_edit_with_count, selectedCount));
        }
    }

    private void updateResultButtonState(int selectedCount) {
        int required = getRequiredSelectionCount();
        boolean canExport = required > 0 && selectedCount == required;
        btnDirectToResult.setEnabled(canExport);
        btnDirectToResult.setText(getString(R.string.btn_result_with_count, selectedCount, required));
    }

    private int getRequiredSelectionCount() {
        int capturedCount = sessionState.getCapturedImageUris().size();
        if (capturedCount <= 0) {
            return 0;
        }
        return Math.min(REQUIRED_SELECTION_COUNT, capturedCount);
    }

    private Uri getSelectedOriginalUri(Uri currentDisplayUri) {
        if (currentDisplayUri == null) {
            return null;
        }

        List<String> captured = sessionState.getCapturedImageUris();
        for (int i = 0; i < captured.size(); i++) {
            String orig = captured.get(i);
            String edit = sessionState.getEditedImageUris().get(orig);
            if (currentDisplayUri.toString().equals(orig) || currentDisplayUri.toString().equals(edit)) {
                return Uri.parse(orig);
            }
        }
        return null;
    }

    private void launchNextEditInQueue() {
        String nextOriginalUri = pendingEditOriginalUris.pollFirst();
        if (nextOriginalUri == null) {
            isBatchEditing = false;
            updateAdapterUris();
            return;
        }

        sessionState.setSelectedImageUri(nextOriginalUri);
        sessionRepository.saveSession(sessionState);

        Intent intent = new Intent(PhotoSelectionActivity.this, EditPhotoActivity.class);
        intent.putExtra(IntentKeys.EXTRA_SELECTED_IMAGE, nextOriginalUri);
        editActivityResultLauncher.launch(intent);
    }

    private void updateSelectedPreviewStrip(List<Uri> selectedUris) {
        selectedPhotoPreviewAdapter.setSelectedUris(selectedUris);
    }

    private void setupToolbar() {
        MaterialToolbar toolbar = findViewById(R.id.topAppBar);
        setSupportActionBar(toolbar);
        if (getSupportActionBar() != null) {
            getSupportActionBar().setDisplayHomeAsUpEnabled(true);
        }
        toolbar.setNavigationIcon(R.drawable.ic_arrow_back_24);
        toolbar.setNavigationOnClickListener(v -> getOnBackPressedDispatcher().onBackPressed());
    }

    private void showSelectionHelpDialog() {
        int requiredCount = getRequiredSelectionCount();
        HelpDialogUtils.showPhotoboothHelp(
                this,
                getString(R.string.help_selection_title),
                getString(R.string.help_selection_subtitle),
                Arrays.asList(
                        getString(R.string.help_selection_bullet_1, requiredCount),
                        getString(R.string.help_selection_bullet_2),
                        getString(R.string.help_selection_bullet_3, requiredCount)
                )
        );
    }

    @Override
    public boolean onSupportNavigateUp() {
        getOnBackPressedDispatcher().onBackPressed();
        return true;
    }
}
